 const pendaisonDeCremaillere = "{\"parsed\":{\"_path\":\"/fr/_archived/pendaison-de-cremaillere\",\"_dir\":\"_archived\",\"_draft\":false,\"_partial\":true,\"_locale\":\"\",\"title\":\"On a fini de faire le ménage\",\"description\":\"Je viens de terminer la configuration de mon tout nouveau blog, et je dois dire... c’est une petite révolution ! Un grand merci à Matt Mullenweg, qui m’a sans le savoir donné le coup de pouce nécessaire pour me lancer dans cette aventure.\",\"image\":\"/images/articles/mouff.jpg\",\"createdAt\":\"21-10-2024\",\"id\":2,\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"on-a-fini-de-faire-le-ménage\"},\"children\":[{\"type\":\"text\",\"value\":\"On a fini de faire le ménage\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je viens de terminer la configuration de mon tout nouveau blog, et je dois dire... c’est une petite révolution ! Un grand merci à Matt Mullenweg, qui m’a sans le savoir donné le coup de pouce nécessaire pour me lancer dans cette aventure.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais plus sérieusement, j'ai choisi d’abandonner WordPress et de plonger dans le monde de Nuxt 3. Vous vous demandez peut-être pourquoi ? Eh bien, voici quelques raisons qui m’ont convaincu que Nuxt 3 est la stack qu’il me fallait .\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Nuxt génère le site rapidement;\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il n'y a plus de base de données ou de plugin à gérer;\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Les commentaires sont gérés depuis Disqus;\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Les correctifs sont faciles à appliquer et déployer , via Git;\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais surtout, rédiger mes articles en Markdown, c’est juste génial. Plus besoin de batailler avec Gutenberg (même si je l'aime bien...) ou l’éditeur de WordPress. Simplicité et efficacité au rendez-vous !\"}]}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[]}},\"_type\":\"markdown\",\"_id\":\"content:fr:_archived:pendaison-de-cremaillere.md\",\"_source\":\"content\",\"_file\":\"fr/_archived/pendaison-de-cremaillere.md\",\"_stem\":\"fr/_archived/pendaison-de-cremaillere\",\"_extension\":\"md\"},\"hash\":\"9phvxRMD45\"}";

